import{_ as i,o as e,c as l,a3 as r}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"基础入口","description":"易经入门先建立方法感，而不是急着记忆所有内容。","frontmatter":{"title":"基础入口","description":"易经入门先建立方法感，而不是急着记忆所有内容。"},"headers":[],"relativePath":"yijing/basics/index.md","filePath":"yijing/basics/index.md","lastUpdated":1777132262000}'),t={name:"yijing/basics/index.md"};function o(n,a,s,h,d,c){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="基础入口" tabindex="-1">基础入口 <a class="header-anchor" href="#基础入口" aria-label="Permalink to &quot;基础入口&quot;">​</a></h1><p>《易经》最难的，往往不是“内容太玄”，而是读者一开始就不知道自己该先抓什么。</p><p>最常见的起手误区有三个：</p><ul><li>一上来就想把六十四卦全部记住</li><li>一开始就陷入术语堆和老师说法差异</li><li>只看占断结果，却没有先学观察变化的方式</li></ul><p>所以这里不求一步到位，而是先把进入《易经》的三块地基搭稳：</p><ol><li>建阅读方法</li><li>建核心概念表</li><li>建六十四卦目录感</li></ol><h2 id="为什么先从这里开始" tabindex="-1">为什么先从这里开始 <a class="header-anchor" href="#为什么先从这里开始" aria-label="Permalink to &quot;为什么先从这里开始&quot;">​</a></h2><p>基础入口不是“前言”，而是后面所有阅读的承接层。</p><ul><li>学习方法，解决“怎么学才不乱”</li><li>核心概念，解决“这些词到底是什么意思”</li><li>卦象目录，解决“整体结构感从哪里来”</li></ul><p>若这三层没有先立住，后面无论读《系辞》《说卦》，还是逐卦笔记，都容易只剩零散印象。</p><h2 id="建议进入顺序" tabindex="-1">建议进入顺序 <a class="header-anchor" href="#建议进入顺序" aria-label="Permalink to &quot;建议进入顺序&quot;">​</a></h2><h3 id="第一步-先学怎么看" tabindex="-1">第一步：先学怎么看 <a class="header-anchor" href="#第一步-先学怎么看" aria-label="Permalink to &quot;第一步：先学怎么看&quot;">​</a></h3><p>先看 <a href="/Dao/yijing/basics/learning-method">学习方法</a>，先明白《易经》不是单纯的卜筮结果表，而是一套看变化、看位置、看关系、看时机的方式。</p><h3 id="第二步-再稳住词汇" tabindex="-1">第二步：再稳住词汇 <a class="header-anchor" href="#第二步-再稳住词汇" aria-label="Permalink to &quot;第二步：再稳住词汇&quot;">​</a></h3><p>接着看 <a href="/Dao/yijing/basics/core-concepts">核心概念</a>，把阴阳、刚柔、中正、位、应、时、变易、象理用这些最常出现的词先安顿下来。</p><h3 id="第三步-最后建立卦象目录感" tabindex="-1">第三步：最后建立卦象目录感 <a class="header-anchor" href="#第三步-最后建立卦象目录感" aria-label="Permalink to &quot;第三步：最后建立卦象目录感&quot;">​</a></h3><p>再进入 <a href="/Dao/yijing/hexagrams/">六十四卦目录</a>，先知道整部书的大体结构，而不是急着每一卦都读透。</p><h2 id="进入这一部分时-先记住三句话" tabindex="-1">进入这一部分时，先记住三句话 <a class="header-anchor" href="#进入这一部分时-先记住三句话" aria-label="Permalink to &quot;进入这一部分时，先记住三句话&quot;">​</a></h2><ul><li>先求不乱，再求深</li><li>先会观察，再谈判断</li><li>先建结构，再积材料</li></ul><h2 id="当前可直接进入的页面" tabindex="-1">当前可直接进入的页面 <a class="header-anchor" href="#当前可直接进入的页面" aria-label="Permalink to &quot;当前可直接进入的页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/learning-method">学习方法</a></li><li><a href="/Dao/yijing/basics/core-concepts">核心概念</a></li><li><a href="/Dao/yijing/hexagrams/">六十四卦目录</a></li></ul>',21)])])}const b=i(t,[["render",o]]);export{u as __pageData,b as default};
